gcode_macros.gcode:
[homing_override]
axes: xyz
set_position_z: 0
gcode:
    {% set coarse_current_x = 1.0 %}
    {% set coarse_current_y = 1.2 %}
    {% set retract_coarse = 8 %}
    {% set coarse_travel = 3000 %}
    {% set fine_current_x = 0.5 %}
    {% set fine_current_y = 0.6 %}
    {% set retract_fine = 3 %}
    {% set fine_travel = 900 %}
    {% set run_current = 1.2 %}
    {% set homing_travel_speed = 1800 %}
    {% set x_max = printer.configfile.settings.stepper_x.position_max|float %}
    {% set x_min = printer.configfile.settings.stepper_x.position_min|float %}
    {% set y_max = printer.configfile.settings.stepper_y.position_max|float %}
    {% set y_min = printer.configfile.settings.stepper_y.position_min|float %}
    {% set mesh_min = printer.configfile.settings.bed_mesh.mesh_min %}
    {% set mesh_max = printer.configfile.settings.bed_mesh.mesh_max %}
    {% set x_center = (mesh_min[0]|float + mesh_max[0]|float) / 2 %}
    {% set y_center = (mesh_min[1]|float + mesh_max[1]|float) / 2 %}
    {% set home_all = 'X' not in params and 'Y' not in params and 'Z' not in params %}
    G90
    SET_KINEMATIC_POSITION Z=0
    G1 Z20 F300
    SET_KINEMATIC_POSITION X={x_max} Y={y_min}
    G1 X{x_max - retract_coarse} Y{y_min + retract_coarse} F{coarse_travel}
    SET_TMC_FIELD STEPPER=stepper_x FIELD=tcoolthrs VALUE=0
    SET_TMC_FIELD STEPPER=stepper_y FIELD=tcoolthrs VALUE=0
    {% if home_all or 'X' in params %}
        SET_TMC_CURRENT STEPPER=stepper_x CURRENT={coarse_current_x}
        G28 X
        G91
        G1 X-{retract_coarse} F{coarse_travel}
        G90
        SET_TMC_CURRENT STEPPER=stepper_x CURRENT={fine_current_x}
        G28 X
        G91
        G1 X-{retract_fine} F{fine_travel}
        G90
        SET_TMC_CURRENT STEPPER=stepper_x CURRENT={run_current}
    {% endif %}
    {% if home_all or 'Y' in params %}
        SET_TMC_CURRENT STEPPER=stepper_y CURRENT={coarse_current_y}
        G28 Y
        G91
        G1 Y{retract_coarse} F{coarse_travel}
        G90
        SET_TMC_CURRENT STEPPER=stepper_y CURRENT={fine_current_y}
        G28 Y
        G91
        G1 Y{retract_fine} F{fine_travel}
        G90
        SET_TMC_CURRENT STEPPER=stepper_y CURRENT={run_current}
    {% endif %}
    {% if home_all or 'Z' in params %}
        {% if not home_all %}
            SET_TMC_CURRENT STEPPER=stepper_x CURRENT={coarse_current_x}
            G28 X
            G91
            G1 X-{retract_coarse} F{coarse_travel}
            G90
            SET_TMC_CURRENT STEPPER=stepper_x CURRENT={fine_current_x}
            G28 X
            G91
            G1 X-{retract_fine} F{fine_travel}
            G90
            SET_TMC_CURRENT STEPPER=stepper_x CURRENT={run_current}
            SET_TMC_CURRENT STEPPER=stepper_y CURRENT={coarse_current_y}
            G28 Y
            G91
            G1 Y{retract_coarse} F{coarse_travel}
            G90
            SET_TMC_CURRENT STEPPER=stepper_y CURRENT={fine_current_y}
            G28 Y
            G91
            G1 Y{retract_fine} F{fine_travel}
            G90
            SET_TMC_CURRENT STEPPER=stepper_y CURRENT={run_current}
        {% endif %}
        {% set z_max = printer.configfile.settings.stepper_z.position_max|float %}
        SET_KINEMATIC_POSITION Z={z_max}
        YUMI_Z_TAP SAVE=0
        G1 X{x_max} F{homing_travel_speed}
    {% endif %}
    AUTOTUNE_TMC STEPPER=stepper_x
    AUTOTUNE_TMC STEPPER=stepper_y

[delayed_gcode welcome]
initial_duration: 1
gcode:
    {% set x_max = printer.configfile.settings.stepper_x.position_max|float %}
    {% if x_max >= 245 and x_max <= 275 %}
        {% set model = "C235" %}
        {% set bed_size = 235 %}
    {% elif x_max >= 345 and x_max <= 375 %}
        {% set model = "C335" %}
        {% set bed_size = 335 %}
    {% elif x_max >= 445 and x_max <= 475 %}
        {% set model = "C435" %}
        {% set bed_size = 435 %}
    {% else %}
        {% set model = "UNKNOWN" %}
        {% set bed_size = 0 %}
    {% endif %}
    {% set has_smartbox = 'mcu smartbox' in printer %}
    {% set ns = namespace(yms=0) %}
    {% if 'extruder_stepper extruder0' in printer.configfile.settings %}{% set ns.yms = ns.yms + 1 %}{% endif %}
    {% if 'extruder_stepper extruder1' in printer.configfile.settings %}{% set ns.yms = ns.yms + 1 %}{% endif %}
    {% if 'extruder_stepper extruder2' in printer.configfile.settings %}{% set ns.yms = ns.yms + 1 %}{% endif %}
    {% if 'extruder_stepper extruder3' in printer.configfile.settings %}{% set ns.yms = ns.yms + 1 %}{% endif %}
    {% if 'extruder_stepper extruder4' in printer.configfile.settings %}{% set ns.yms = ns.yms + 1 %}{% endif %}
    {% if 'extruder_stepper extruder5' in printer.configfile.settings %}{% set ns.yms = ns.yms + 1 %}{% endif %}
    {% if 'extruder_stepper extruder6' in printer.configfile.settings %}{% set ns.yms = ns.yms + 1 %}{% endif %}
    {% set ns2 = namespace(dryer_pos="none", has_dryer=false) %}
    {% if 'heater_generic yms-3-pro' in printer.configfile.settings %}{% set ns2.has_dryer = true %}{% set ns2.dryer_pos = "YMS-3" %}{% endif %}
    {% set yms_type = "PRO" if ns2.has_dryer else ("LITE" if ns.yms > 0 else "NONE") %}
    {% set has_probe_pressure = 'probe_pressure' in printer.configfile.settings %}
    {% set probe_type = "pressure" if has_probe_pressure else "standard" %}
    {% set has_adxl = 'mcu rpi' in printer %}
    {% if ns.yms > 0 %}
        {% set full_model = model ~ " " ~ ns.yms ~ "YMS-" ~ yms_type %}
    {% else %}
        {% set full_model = model ~ " 1COLOR" %}
    {% endif %}
    SAVE_VARIABLE VARIABLE=machine_model VALUE="'{model}'"
    SAVE_VARIABLE VARIABLE=machine_full_model VALUE="'{full_model}'"
    SAVE_VARIABLE VARIABLE=machine_bed_size VALUE={bed_size}
    SAVE_VARIABLE VARIABLE=machine_yms_count VALUE={ns.yms}
    SAVE_VARIABLE VARIABLE=machine_yms_type VALUE="'{yms_type}'"
    SAVE_VARIABLE VARIABLE=machine_has_smartbox VALUE={1 if has_smartbox else 0}
    SAVE_VARIABLE VARIABLE=machine_probe_type VALUE="'{probe_type}'"
    SAVE_VARIABLE VARIABLE=machine_has_adxl VALUE={1 if has_adxl else 0}
    BED_MESH_PROFILE LOAD=default
    RESPOND MSG="YUMI {full_model} | Probe:{probe_type} | ADXL:{'yes' if has_adxl else 'no'} | Smartbox:{'yes' if has_smartbox else 'no'}"
    M117 {full_model}

[gcode_macro SET_GCODE_OFFSET]
rename_existing: _SET_GCODE_OFFSET
gcode:
    {% if printer.save_variables.variables.gcode_offsets %}
        {% set offsets = printer.save_variables.variables.gcode_offsets %}
    {% else %}
        {% set offsets = {'x': None,'y': None,'z': None} %}
    {% endif %}
    {% set ns = namespace(offsets={'x': offsets.x,'y': offsets.y,'z': offsets.z}) %}
    _SET_GCODE_OFFSET {% for p in params %}{'%s=%s '% (p, params[p])}{% endfor %}
    {%if 'X' in params %}{% set null = ns.offsets.update({'x': params.X}) %}{% endif %}
    {%if 'Y' in params %}{% set null = ns.offsets.update({'y': params.Y}) %}{% endif %}
    {%if 'Z' in params %}{% set null = ns.offsets.update({'z': params.Z}) %}{% endif %}
    {%if 'Z_ADJUST' in params %}
        {%if ns.offsets.z == None %}{% set null = ns.offsets.update({'z': 0}) %}{% endif %}
        {% set null = ns.offsets.update({'z': (ns.offsets.z | float) + (params.Z_ADJUST | float)}) %}
    {% endif %}
    SAVE_VARIABLE VARIABLE=gcode_offsets VALUE="{ns.offsets}"

[gcode_macro PAUSE]
description: Pause the running print
rename_existing: PAUSE_BASE
variable_extrude: 5.0
gcode:
    SAVE_VARIABLE VARIABLE=fan_speed VALUE={printer.fan.speed * 255}
    {% set act_x = printer.toolhead.position.x|float %}
    {% set act_y = printer.toolhead.position.y|float %}
    {% set act_z = printer.toolhead.position.z|float %}
    SAVE_VARIABLE VARIABLE=pause_x VALUE={act_x}
    SAVE_VARIABLE VARIABLE=pause_y VALUE={act_y}
    SAVE_VARIABLE VARIABLE=pause_z VALUE={act_z}
    M106 S0
    {% set E = printer["gcode_macro PAUSE"].extrude|float %}
    {% set x_park = printer.toolhead.axis_maximum.x|float %}
    {% set y_park = printer.toolhead.axis_maximum.y|float / 2 %}
    {% set max_z = printer.toolhead.axis_maximum.z|float %}
    {% set act_z = printer.toolhead.position.z|float %}
    {% if act_z < (max_z - 2.0) %}
        {% set z_safe = 2.0 %}
    {% else %}
        {% set z_safe = max_z - act_z %}
    {% endif %}
    PAUSE_BASE
    G91
    {% if printer.extruder.can_extrude|lower == 'true' %}
        G1 E-{E} F2100
    {% else %}
        {action_respond_info("Extruder not hot enough")}
    {% endif %}
    {% if "xyz" in printer.toolhead.homed_axes %}
        G1 Z{z_safe} F900
        G90
        G1 X{x_park} Y{y_park} F6000
    {% else %}
        {action_respond_info("Printer not homed")}
    {% endif %}
    M117 pause print

[gcode_macro RESUME]
description: Resume the running print
rename_existing: RESUME_BASE
variable_prime: 40.0
gcode:
    {% set svv = printer.save_variables.variables %}
    {% set fan_speed = svv.fan_speed|default(0)|int %}
    {% set x_park = printer.toolhead.axis_maximum.x|float %}
    G1 X{x_park} F6000
    {% if 'pause_x' in svv and 'pause_y' in svv and 'pause_z' in svv %}
        {% set px = svv.pause_x|float %}
        {% set py = svv.pause_y|float %}
        {% set pz = svv.pause_z|float %}
    {% else %}
        {action_respond_info("Pause coordinates not found")}
        M117 ERROR: Unknown pause position
    {% endif %}
    {% set E = printer["gcode_macro PAUSE"].extrude|float %}
    {% if 'VELOCITY' in params|upper %}
        {% set get_params = ('VELOCITY=' + params.VELOCITY) %}
    {% else %}
        {% set get_params = "" %}
    {% endif %}
    {% if printer.extruder.can_extrude|lower == 'true' %}
        G91
        G1 E{prime|float} F300
        G92 E0
        M106 S255
        G4 P5000
        G90
        G1 X{x_park - 11} F26000
        G92 E0
        G1 X{px} Y{py} Z{pz} F6000
        G1 E{E} F10800
        M106 S{fan_speed}
    {% else %}
        {action_respond_info("Extruder not hot enough")}
    {% endif %}
    RESUME_BASE {get_params}
    M117 printing...

[gcode_macro CANCEL_PRINT]
rename_existing: CANCEL_PRINT_DEFAULT
description: Cancel print, retract & park head safely
gcode:
    CANCEL_PRINT_DEFAULT
    M220 S100
    M221 S100
    SAVE_VARIABLE VARIABLE=was_interrupted VALUE=False
    SAVE_VARIABLE VARIABLE=printing_start VALUE=False
    {% set x_max = printer.configfile.settings.stepper_x.position_max|float %}
    {% if x_max >= 245 and x_max <= 275 %}
        {% set bed_size = 235 %}
    {% elif x_max >= 345 and x_max <= 375 %}
        {% set bed_size = 335 %}
    {% elif x_max >= 445 and x_max <= 475 %}
        {% set bed_size = 435 %}
    {% else %}
        {% set bed_size = 235 %}
    {% endif %}
    {% set y_park = printer.configfile.settings.stepper_y.position_max|float %}
    {% set z_max = printer.toolhead.axis_maximum.z|float %}
    {% set z_lift = 10.0 %}
    SET_VELOCITY_LIMIT ACCEL=20000 ACCEL_TO_DECEL=10000
    G92 E0
    G1 E-7 F4800
    G1 E-10 F2100
    G1 E-20 F300
    G91
    {% set dz = z_lift if (printer.gcode_move.position.z + z_lift) < z_max else (z_max - printer.gcode_move.position.z) %}
    G1 Z+{dz} F3000
    G90
    G1 X{bed_size + 11} F26000
    G1 X{bed_size + 25} F5000
    SET_VELOCITY_LIMIT ACCEL=9000 ACCEL_TO_DECEL=4500
    G1 Y{y_park} F3000
    SET_VELOCITY_LIMIT ACCEL=20000 ACCEL_TO_DECEL=10000
    G92 E0
    G1 E-110 F2100
    M106 S0
    G92 E0
    ALL_FAN_OFF
    TURN_OFF_HEATERS
    M84

[gcode_macro UNLOAD_FILAMENT]
description: Unload filament with auto-heat
gcode:
    {% if printer.idle_timeout.state == "Printing" %}
        {action_respond_info("Can't unload while printing!")}
    {% else %}
        {% if printer.extruder.temperature < 200 %}
            M109 S{params.TEMP|default(220)}
        {% endif %}
        G90
        G1 X0 F5000
        G1 X-12 F2000
        G92 E0
        G1 E-30 F800
        G1 X20 F5000
        RESPOND MSG="Filament unloaded"
    {% endif %}

[gcode_macro LOAD_FILAMENT]
description: Load filament with auto-heat
gcode:
    {% if printer.idle_timeout.state == "Printing" %}
        {action_respond_info("Can't load while printing!")}
    {% else %}
        {% if printer.extruder.temperature < 200 %}
            M109 S{params.TEMP|default(220)}
        {% endif %}
        G91
        G1 E50 F800
        G1 E30 F150
        G90
        RESPOND MSG="Filament loaded"
    {% endif %}

[gcode_macro PID_CALIBRATION]
description: PID calibration — PID_CALIBRATION / PID_CALIBRATION BED=70 HOTEND=250
gcode:
    {% if printer.idle_timeout.state == "Printing" %}
        {action_respond_info("Can't run this macro right now!")}
    {% else %}
        {% set bed_temp = params.BED|default(65)|int %}
        {% set hotend_temp = params.HOTEND|default(220)|int %}
        {% set do_save = true if params.SAVE is not defined or params.SAVE|upper != "NO" else false %}
        {action_respond_info("PID Calibration — Bed:%dC Hotend:%dC Save:%s" % (bed_temp, hotend_temp, "yes" if do_save else "no"))}
        BED_DETECTION
        G1 Z50 F1500
        M400
        {action_respond_info("Phase 1/2 — Bed PID at %dC..." % bed_temp)}
        PID_CALIBRATE HEATER=heater_bed TARGET={bed_temp}
        M400
        {action_respond_info("Phase 2/2 — Hotend PID at %dC..." % hotend_temp)}
        M106
        PID_CALIBRATE HEATER=extruder TARGET={hotend_temp}
        M107
        M400
        TURN_OFF_HEATERS
        {% if do_save %}
            {action_respond_info("PID Calibration done — saving...")}
            SAVE_CONFIG
        {% else %}
            {action_respond_info("PID Calibration done — NOT saved (SAVE=NO).")}
        {% endif %}
    {% endif %}

[gcode_macro ADXL_AXE_X]
description: X axis resonance calibration
gcode:
    {% if printer.idle_timeout.state == "Printing" %}
        {action_respond_info("Can't run this macro right now!")}
    {% else %}
        {% if printer.toolhead.homed_axes != "xyz" %}
            G28
        {% endif %}
        M400
        SHAPER_CALIBRATE AXIS=X
    {% endif %}

[gcode_macro ADXL_AXE_Y]
description: Y axis resonance calibration
gcode:
    {% if printer.idle_timeout.state == "Printing" %}
        {action_respond_info("Can't run this macro right now!")}
    {% else %}
        {% if printer.toolhead.homed_axes != "xyz" %}
            G28
        {% endif %}
        M400
        SHAPER_CALIBRATE AXIS=Y
    {% endif %}

[gcode_macro SAVECONFIG]
gcode:
    SAVE_CONFIG

[gcode_macro M106]
rename_existing: M106.1
gcode:
    {% set S = params.S|default(255)|int %}
    {% if params.P is defined %}
        {% set P = params.P|int %}
        {% if P == 2 %}
            SET_FAN_SPEED FAN=Aux_Fan SPEED={S / 255.0}
        {% elif P == 3 %}
            SET_FAN_SPEED FAN=Motherboard_Fan SPEED={S / 255.0}
        {% else %}
            M106.1 S{S}
        {% endif %}
    {% else %}
        M106.1 S{S}
    {% endif %}

[gcode_macro M107]
rename_existing: M107.1
gcode:
    {% if params.P is defined %}
        {% set P = params.P|int %}
        {% if P == 2 %}
            SET_FAN_SPEED FAN=Aux_Fan SPEED=0
        {% elif P == 3 %}
            SET_FAN_SPEED FAN=Motherboard_Fan SPEED=0
        {% else %}
            M107.1
        {% endif %}
    {% else %}
        M107.1
    {% endif %}

[gcode_macro M201]
description: Sets maximum acceleration.
gcode:
    {% if 'X' in params or 'Y' in params %}
        {% set accel = (params.X|default(params.Y)|float, params.Y|default(params.X)|float)|min %}
        SET_VELOCITY_LIMIT ACCEL={accel} ACCEL_TO_DECEL={accel * 0.5}
    {% else %}
        SET_VELOCITY_LIMIT
    {% endif %}

[gcode_macro M203]
description: Sets maximum velocity.
gcode:
    {% if 'X' in params or 'Y' in params %}
        {% set velocity = (params.X|default(params.Y)|float, params.Y|default(params.X)|float)|min %}
        SET_VELOCITY_LIMIT VELOCITY="{velocity}"
    {% else %}
        SET_VELOCITY_LIMIT
    {% endif %}

[gcode_macro M205]
description: Sets square corner velocity.
gcode:
    {% if 'X' in params or 'Y' in params %}
        SET_VELOCITY_LIMIT SQUARE_CORNER_VELOCITY="{(params.X|default(0)|float, params.Y|default(0)|float)|min}"
    {% else %}
        SET_VELOCITY_LIMIT
    {% endif %}

[gcode_macro M900]
description: Set Pressure Advance.
gcode:
    {% if 'K' in params %}
        SET_PRESSURE_ADVANCE ADVANCE={params.K}
    {% endif %}

[gcode_macro Z_TAP]
description: Set Z=0 via nozzle tap (probe pressure). Auto-detects printing state.
gcode:
    {% set SAVE_PARAM = params.SAVE|default(0)|int %}
    {% set is_printing = printer.idle_timeout.state == "Printing" %}
    {% if is_printing %}
        M109 S150
        WIPE_NOZZLE
        YUMI_Z_TAP SAVE={SAVE_PARAM}
        M104 S0
    {% else %}
        {% if printer.toolhead.homed_axes != "xyz" %}
            G28
        {% endif %}
        {% set z_max = printer.configfile.settings.stepper_z.position_max|float %}
        SET_KINEMATIC_POSITION Z={z_max}
        YUMI_Z_TAP SAVE={SAVE_PARAM}
    {% endif %}

[gcode_macro BED_DETECTION]
description: Detect bed presence via 2-point probe
gcode:
    {% set ref_offset_x = 8.5 %}
    {% set ref_offset_y = 22 %}
    {% set bed_probe_x_inset = 14 %}
    {% set x_max = printer.configfile.settings.stepper_x.position_max|float %}
    {% set z_max = printer.configfile.settings.stepper_z.position_max|float %}
    {% if x_max >= 245 and x_max <= 275 %}
        {% set bed_size = 235 %}
    {% elif x_max >= 345 and x_max <= 375 %}
        {% set bed_size = 335 %}
    {% elif x_max >= 445 and x_max <= 475 %}
        {% set bed_size = 435 %}
    {% else %}
        {% set bed_size = 235 %}
    {% endif %}
    {% set ref_x = bed_size / 2 + ref_offset_x %}
    {% set ref_y = bed_size - ref_offset_y %}
    {% set probe_x = x_max - bed_probe_x_inset %}
    {% set probe_y = ref_y %}
    G28 X
    G28 Y
    SET_KINEMATIC_POSITION Z={z_max - 20}
    G90
    G1 X{ref_x} Y{ref_y} F12000
    PROBE
    SET_KINEMATIC_POSITION Z=0
    G1 Z10 F500
    G1 X{probe_x} Y{probe_y} F12000
    PROBE
    SET_KINEMATIC_POSITION Z=0
    G1 Z10 F500
    G1 X{x_max} F9000

[gcode_macro PROBE_CALIBRATE]
rename_existing: BASE_PROBE_CALIBRATE
gcode:
    {% set mesh_min = printer.configfile.settings.bed_mesh.mesh_min %}
    {% set mesh_max = printer.configfile.settings.bed_mesh.mesh_max %}
    {% set bed_cx = (mesh_min[0]|float + mesh_max[0]|float) / 2 %}
    {% set bed_cy = (mesh_min[1]|float + mesh_max[1]|float) / 2 %}
    BED_DETECTION
    G1 X{bed_cx} Y{bed_cy} F12000
    BASE_PROBE_CALIBRATE

[gcode_macro SCREWS_TILT_CALCULATE]
rename_existing: BASE_SCREWS_TILT_CALCULATE
gcode:
    {% set x_max = printer.configfile.settings.stepper_x.position_max|float %}
    {% if x_max >= 245 and x_max <= 275 %}
        {% set bed_size = 235 %}
    {% elif x_max >= 345 and x_max <= 375 %}
        {% set bed_size = 335 %}
    {% elif x_max >= 445 and x_max <= 475 %}
        {% set bed_size = 435 %}
    {% else %}
        {% set bed_size = 235 %}
    {% endif %}
    {% set y_park = printer.configfile.settings.stepper_y.position_max|float %}
    M140 S50
    BED_DETECTION
    BASE_SCREWS_TILT_CALCULATE
    G1 Z20 F500
    G1 X{bed_size / 2} Y{y_park - 2} F6000
    M140 S0

[gcode_macro BED_MESH_CALIBRATE]
rename_existing: BASE_BED_MESH_CALIBRATE
description: Bed mesh with preheat and auto homing
gcode:
    {% set profile_name = params.PROFILE|default('default')|string %}
    BED_DETECTION
    G1 Z100
    M190 S65
    G4 P60000
    BASE_BED_MESH_CALIBRATE PROFILE={profile_name}
    BED_MESH_PROFILE SAVE={profile_name}
    SAVE_CONFIG

[gcode_macro WIPE_NOZZLE]
description: Wipe nozzle on brush
gcode:
        {% if printer.extruder.temperature < 125 %}
            M109 S130
        {% endif %}
        {% set x_max = printer.configfile.settings.stepper_x.position_max|float %}
        {% if x_max >= 245 and x_max <= 275 %}
            {% set bed_size = 235 %}
        {% elif x_max >= 345 and x_max <= 375 %}
            {% set bed_size = 335 %}
        {% elif x_max >= 445 and x_max <= 475 %}
            {% set bed_size = 435 %}
        {% else %}
            {% set bed_size = 235 %}
        {% endif %}
        {% set brush_x_min = bed_size / 2 + 18.5 %}
        {% set brush_x_max = bed_size / 2 + 45.5 %}
        {% set brush_y_min = bed_size + 6 %}
        {% set brush_y_max = bed_size + 11 %}
        {% set brush_z = 2.5 %}
        {% set wipe_passes = 4 %}
        {% set wipe_speed = 6000 %}
        {% if printer.toolhead.homed_axes != "xyz" %}
            G28
        {% endif %}
        G90
        G1 Z10 F300
        G1 X{brush_x_min} Y{brush_y_min} F6000
        G1 Z{brush_z} F300
        {% for pass in range(wipe_passes) %}
            G1 X{brush_x_min} Y{brush_y_min} F{wipe_speed}
            G1 X{brush_x_max} Y{brush_y_max} F{wipe_speed}
            G1 X{brush_x_min} Y{brush_y_max} F{wipe_speed}
            G1 X{brush_x_max} Y{brush_y_min} F{wipe_speed}
        {% endfor %}
        G1 Z10 F300
        RESPOND MSG="Nozzle wiped"

[gcode_macro SET_HEATER_TEMPERATURE]
rename_existing: SET_HEATER_TEMPERATURE_ORIG
gcode:
    {% set heater = params.HEATER|default("") %}
    {% set target = params.TARGET|default(0)|float %}
    {% if heater in ["YMS-3-PRO", "YMS-4-PRO", "YMS-5-PRO", "YMS-8-PRO", "YMS-9-PRO", "YMS-10-PRO"] and target > 110 %}
        RESPOND TYPE=error MSG="ERROR: { heater } temperature limited to 110C"
        SET_HEATER_TEMPERATURE_ORIG HEATER={heater} TARGET=110
    {% else %}
        SET_HEATER_TEMPERATURE_ORIG HEATER={heater} TARGET={target}
    {% endif %}

[gcode_macro SET_EXTRA_FLUSH]
description: Set purge parameters
gcode:
    {% if 'LENGTH' in params %}
        {% set new_length = params.LENGTH|float %}
        SAVE_VARIABLE VARIABLE=extra_purge_length VALUE={new_length}
        { action_respond_info("Purge length set to %.1fmm" % new_length) }
    {% endif %}
    {% if 'SPEED' in params %}
        {% set new_speed = params.SPEED|float %}
        SAVE_VARIABLE VARIABLE=extra_purge_speed VALUE={new_speed}
        { action_respond_info("Purge speed set to %.1fmm/s" % new_speed) }
    {% endif %}

[gcode_macro EXTRA_FLUSH]
description: Extrude extra filament
gcode:
    {% set svv = printer.save_variables.variables %}
    {% set length = svv.extra_purge_length|default(0)|float %}
    {% set speed = svv.extra_purge_speed|default(5)|float %}
    {% if printer.extruder.can_extrude|lower == 'true' %}
        G92 E0
        G1 E{length} F{speed * 60}
        { action_respond_info("Purge: %.1fmm @ %.1fmm/s" % (length, speed)) }
    {% else %}
        { action_respond_error("ERROR: Temperature too low!") }
    {% endif %}

[gcode_macro INIT_FLUSH_VARS]
description: Initialize purge variables
gcode:
    {% if 'extra_purge_length' not in printer.save_variables.variables %}
        SAVE_VARIABLE VARIABLE=extra_purge_length VALUE=0.0
    {% endif %}
    {% if 'extra_purge_speed' not in printer.save_variables.variables %}
        SAVE_VARIABLE VARIABLE=extra_purge_speed VALUE=5.0
    {% endif %}

[delayed_gcode INIT_YMS]
initial_duration: 0.01
gcode:
    RESPOND TYPE=error MSG="INIT YMS"
    M117 INIT YMS
    INIT_PURGE_VARS
    T0

[gcode_macro LOAD_YMS]
description: Load filament into the YMS
gcode:
    RESPOND TYPE=error MSG="macro LOAD_YMS"
    M117 macro LOAD_YMS
    {% if printer.save_variables.variables.printing_start %}
        {% set insert_length = 200|int %}
        {% set speed = 1000|int %}
        G92 E0
        G1 E{insert_length} F{speed}
        G92 E0
        RESPOND MSG="Filament loaded {insert_length}mm at {speed}mm/min"
    {% else %}
        {% set insert_length = 50|int %}
        {% set speed = 1000|int %}
        G92 E0
        G1 E{insert_length} F{speed}
        G92 E0
        RESPOND MSG="Filament loaded {insert_length}mm at {speed}mm/min"
        T0
    {% endif %}
